      "keystrokes": "python3 - <<'PY'
import re,struct
bytes_data=bytearray()
base=None
for line in open('/tmp/rodata.txt'):
    m=re.match(r'\s*([0-9a-f]+)\s+((?:[0-9a-f]{2}\s)+)',line)
    if not m: continue
    addr=int(m.group(1),16); hexb=m.group(2).split()
    if base is None: base=addr
    # assume contiguous
    bytes_data.extend(int(x,16) for x in hexb)
print('base',hex(base),'len',len(bytes_data))
for off in range(0,len(bytes_data)-3,4):
    b=bytes_data[off:off+4]
    fv=struct.unpack('<f',b)[0]
    # also show as ints if small integer
    iv=struct.unpack('<I',b)[0]
    s=bytes_data[off:off+16].split(b'\0')[0]
    txt=''
    if 32<=s[0]<127:
        txt=' text='+repr(s[:32])
    if abs(fv)<1e9 and (fv!=0 or iv==0):
        print(f'{base+off:#06x}: {fv:.9g}  u={iv:#010x}{txt}')
PY
